#include <iostream>
#include <string>

class Book {
public:
    std::string title;
    std::string author;

    Book(std::string t, std::string a) : title(t), author(a) {}

    friend std::ostream& operator<<(std::ostream& os, const Book& book);
};

std::ostream& operator<<(std::ostream& os, const Book& book) {
    os << "Title: " << book.title << ", Author: " << book.author;
    return os;
}

int main() {
    Book book1("Test Title 1", "Test Author 1");
    Book book2("Test Title 2", "Test Author 2");
    std::cout << "Book 1: " << book1 << std::endl;
    std::cout << "Book 2: " << book2 << std::endl;
    return 0;
}
